cd /data/e-curricula && python3 -c "
import json, sys
sys.path.insert(0, '.')
from scripts.ingest.parse_slo_document import parse_slo_document, validate_parsed_data

slo = parse_slo_document('input/SLO_SRO_Containers_Cloud_DevOps.docx')
errors = validate_parsed_data(slo)

result = {'status': 'success', 'modules': {}}
if errors:
    result = {'status': 'error', 'errors': errors}
else:
    for key, mod in slo.items():
        result['modules'][key] = {
            'title': mod['title'],
            'sessions': len(mod['sessions']),
            'total_slos': len(mod['sessions']) * 2
        }

print(json.dumps(result))
"

