const sloResult = JSON.parse($('📄 Parse SLO/SRO Document').first().json.stdout);
const sourceResult = JSON.parse($('📚 Extract Source Documents').first().json.stdout);
const config = $('⚙️ Configuration').first().json;

if (sloResult.status === 'error') {
  throw new Error('SLO parsing failed: ' + JSON.stringify(sloResult.errors));
}

// Create one item per module for the loop
const items = [];
for (const moduleNum of config.modules_to_process) {
  const moduleKey = `module_${moduleNum}`;
  const moduleInfo = sloResult.modules[moduleKey];

  if (!moduleInfo) continue;

  items.push({
    json: {
      module_num: moduleNum,
      module_key: moduleKey,
      module_title: moduleInfo.title,
      total_sessions: moduleInfo.sessions,
      total_slos: moduleInfo.total_slos,
      source_info: sourceResult.units[`unit_${moduleNum}`] || { sources: 0, chars: 0 },
      project_path: config.project_path
    }
  });
}

return items;

const genResult = JSON.parse($input.first().json.stdout);
const config = $('⚙️ Configuration').first().json;

if (genResult.status !== 'success') {
  throw new Error('Content generation failed for module ' + genResult.module);
}

return [{
  json: {
    ...genResult,
    project_path: config.project_path
  }
}];

const pptResult = JSON.parse($('📊 Build PPTX Files (18 per module)').first().json.stdout);
const pdfResult = JSON.parse($('📝 Build Learning Material PDF').first().json.stdout);

return [{
  json: {
    module: pptResult.module,
    ppts_created: pptResult.ppts_created,
    pdf_created: pdfResult.status === 'success',
    pdf_path: pdfResult.pdf_path,
    status: 'files_ready'
  }
}];

const config = $('⚙️ Configuration').first().json;
const buildResult = $input.first().json;

if (config.skip_upload) {
  return [{
    json: {
      module: buildResult.module,
      status: 'upload_skipped',
      message: 'Upload skipped — set skip_upload=false and add portal credentials to enable',
      ppts_created: buildResult.ppts_created,
      pdf_created: buildResult.pdf_created
    }
  }];
}

// If upload is enabled, this would call the portal upload script
return [{
  json: {
    module: buildResult.module,
    status: 'ready_for_upload',
    ppts_created: buildResult.ppts_created,
    pdf_created: buildResult.pdf_created
  }
}];

const results = $input.all().map(item => item.json);

let totalPpts = 0;
let totalPdfs = 0;
const moduleResults = [];

for (const r of results) {
  totalPpts += r.ppts_created || 0;
  totalPdfs += r.pdf_created ? 1 : 0;
  moduleResults.push({
    module: r.module,
    ppts: r.ppts_created,
    pdf: r.pdf_created,
    upload: r.status
  });
}

return [{
  json: {
    pipeline_status: 'COMPLETE',
    course: '21CSE597T — Containers and Cloud DevOps',
    total_pptx_files: totalPpts,
    total_pdf_files: totalPdfs,
    total_files: totalPpts + totalPdfs,
    modules_processed: moduleResults,
    output_directory: '/data/e-curricula/output/21CSE597T/',
    timestamp: new Date().toISOString()
  }
}];
